        String nonce = asString(claims.get("nonce"));
        if (expectedNonce != null && !expectedNonce.isBlank()) {
            if (nonce == null || !expectedNonce.equals(nonce)) {
                throw new IllegalArgumentException("Invalid nonce");
            }
        }
